1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import {
3		Check,
4		ChevronDown,
5		ChevronRight,
6		CopyPlus,
7		GitBranch,
8		History,
9		Loader2,
10		PanelLeftClose,
11		PanelLeftOpen,
12		Plus,
13		Search,
14	} from "lucide-react";
15	import { sessions } from "../hooks/keating-storage";
16	import type { SessionMetadata } from "../types/session";
17	import { buildSessionTree, flattenSessionTree } from "./session-tree";
18	
19	const TREE_COLLAPSED_STORAGE_KEY = "keating:session-tree-collapsed";
20	const MD_BREAKPOINT = 768;
21	
22	const SIDEBAR_MIN_W = 288;
23	const SIDEBAR_MAX_W = 640;
24	const SIDEBAR_DEFAULT_W = 360;
25	const SIDEBAR_W_KEY = "keating_session_sidebar_width";
26	
27	interface SessionSidebarProps {
28		activeSessionId?: string;
29		forkingSessionId?: string | null;
30		forkedSessionId?: string | null;
31		collapsed?: boolean;
32		onCollapsedChange?: (next: boolean) => void;
33		onLoad: (sessionId: string) => void | Promise<void>;
34		onFork: (sessionId: string) => void | Promise<void>;
35		onOpenSessions: () => void;
36		mobileOpen?: boolean;
37		onMobileClose?: () => void;
38		onNewSession?: () => void;
39	}
40	
41	function formatDate(isoString: string) {
42		const date = new Date(isoString);
43		const now = new Date();
44		const days = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
45		if (days === 0) return "Today";
46		if (days === 1) return "Yesterday";
47		if (days < 7) return `${days}d ago`;
48		return date.toLocaleDateString();
49	}
50	
51	function readCollapsedTreeNodes(): Set<string> {
52		if (typeof localStorage === "undefined") return new Set();
53		try {
54			const raw = localStorage.getItem(TREE_COLLAPSED_STORAGE_KEY);
55			if (!raw) return new Set();
56			const parsed = JSON.parse(raw);
57			if (!Array.isArray(parsed)) return new Set();
58			return new Set(parsed.filter((value): value is string => typeof value === "string"));
59		} catch {
60			return new Set();
61		}
62	}
63	
64	function writeCollapsedTreeNodes(set: ReadonlySet<string>) {
65		if (typeof localStorage === "undefined") return;
66		try {
67			localStorage.setItem(TREE_COLLAPSED_STORAGE_KEY, JSON.stringify([...set]));
68		} catch {
69			// localStorage may be full or blocked; ignore.
70		}
71	}
72	
73	function loadSidebarWidth(): number {
74		if (typeof localStorage === "undefined") return SIDEBAR_DEFAULT_W;
75		try {
76			const raw = localStorage.getItem(SIDEBAR_W_KEY);
77			if (!raw) return SIDEBAR_DEFAULT_W;
78			const parsed = parseInt(raw, 10);
79			if (isNaN(parsed) || parsed < SIDEBAR_MIN_W || parsed > SIDEBAR_MAX_W) return SIDEBAR_DEFAULT_W;
80			return parsed;
81		} catch {
82			return SIDEBAR_DEFAULT_W;
83		}
84	}
85	
86	function saveSidebarWidth(value: number) {
87		try {
88			localStorage.setItem(SIDEBAR_W_KEY, String(value));
89		} catch {
90			/* noop */
91		}
92	}
93	
94	export function SessionSidebar({
95		activeSessionId,
96		forkingSessionId,
97		forkedSessionId,
98		collapsed = false,
99		onCollapsedChange,
100		onLoad,
101		onFork,
102		onOpenSessions,
103		mobileOpen = false,
104		onMobileClose,
105		onNewSession,
106	}: SessionSidebarProps) {
107		const [items, setItems] = useState<SessionMetadata[]>([]);
108		const [loading, setLoading] = useState(false);
109		const [query, setQuery] = useState("");
110		const [forkedSourceSessionId, setForkedSourceSessionId] = useState<string | null>(null);
111		const [collapsedNodes, setCollapsedNodes] = useState<Set<string>>(() => readCollapsedTreeNodes());
112		const [isDesktop, setIsDesktop] = useState(() =>
113			typeof window !== "undefined"
114				? window.matchMedia(`(min-width: ${MD_BREAKPOINT}px)`).matches
115				: true,
116		);
117		const [sidebarWidth, setSidebarWidth] = useState(loadSidebarWidth);
118		const dragState = useRef({ active: false, startX: 0, startWidth: 0 });
119	
120		useEffect(() => {
121			if (typeof window === "undefined") return;
122			const mq = window.matchMedia(`(min-width: ${MD_BREAKPOINT}px)`);
123			const sync = () => setIsDesktop(mq.matches);
124			mq.addEventListener("change", sync);
125			return () => mq.removeEventListener("change", sync);
126		}, []);
127	
128		const isSearching = query.trim().length > 0;
129	
130		const visibleItems = useMemo(() => {
131			const normalizedQuery = query.trim().toLowerCase();
132			const filtered = items.filter((session) => {
133				if (!normalizedQuery) return true;
134				return [session.title, session.preview, formatDate(session.lastModified)]
135					.some((value) => value.toLowerCase().includes(normalizedQuery));
136			});
137			if (normalizedQuery) {
138				return filtered
139					.map((session) => ({ session, children: [], depth: 0 }))
140					.sort((left, right) => right.session.lastModified.localeCompare(left.session.lastModified))
141					.slice(0, 40);
142			}
143			return flattenSessionTree(buildSessionTree(filtered), collapsedNodes).slice(0, 80);
144		}, [items, query, collapsedNodes]);
145	
146		const reload = async () => {
147			setLoading(true);
148			try {
149				setItems((await sessions.getAllMetadata()) as SessionMetadata[]);
150			} finally {
151				setLoading(false);
152			}
153		};
154	
155		useEffect(() => {
156			void reload();
157			const onChanged = () => void reload();
158			window.addEventListener("keating:sessions-changed", onChanged);
159			return () => window.removeEventListener("keating:sessions-changed", onChanged);
160		}, []);
161	
162		const toggleNode = useCallback((sessionId: string) => {
163			setCollapsedNodes((current) => {
164				const next = new Set(current);
165				if (next.has(sessionId)) {
166					next.delete(sessionId);
167				} else {
168					next.add(sessionId);
169				}
170				writeCollapsedTreeNodes(next);
171				return next;
172			});
173		}, []);
174	
175		const forkSession = async (sessionId: string) => {
176			await onFork(sessionId);
177			setForkedSourceSessionId(sessionId);
178			window.setTimeout(() => {
179				setForkedSourceSessionId((current) => current === sessionId ? null : current);
180			}, 1800);
181		};
182	
183		/* ── Resize handlers ── */
184		const handleResizeStart = useCallback((e: React.MouseEvent | React.TouchEvent) => {
185			e.preventDefault();
186			const clientX = "touches" in e ? e.touches[0].clientX : e.clientX;
187			dragState.current = { active: true, startX: clientX, startWidth: sidebarWidth };
188	
189			const onMove = (moveEvent: MouseEvent | TouchEvent) => {
190				if (!dragState.current.active) return;
191				const moveX = "touches" in moveEvent ? moveEvent.touches[0].clientX : moveEvent.clientX;
192				const delta = moveX - dragState.current.startX;
193				const next = Math.min(SIDEBAR_MAX_W, Math.max(SIDEBAR_MIN_W, dragState.current.startWidth + delta));
194				setSidebarWidth(next);
195			};
196	
197			const onUp = () => {
198				if (!dragState.current.active) return;
199				dragState.current.active = false;
200				document.body.style.cursor = "";
201				document.body.style.userSelect = "";
202				window.removeEventListener("mousemove", onMove);
203				window.removeEventListener("mouseup", onUp);
204				window.removeEventListener("touchmove", onMove);
205				window.removeEventListener("touchend", onUp);
206				setSidebarWidth((w) => {
207					saveSidebarWidth(w);
208					return w;
209				});
210			};
211	
212			document.body.style.cursor = "col-resize";
213			document.body.style.userSelect = "none";
214			window.addEventListener("mousemove", onMove);
215			window.addEventListener("mouseup", onUp);
216			window.addEventListener("touchmove", onMove, { passive: false });
217			window.addEventListener("touchend", onUp);
218		}, [sidebarWidth]);
219	
220		/* ── Mobile drawer ── */
221		if (!isDesktop) {
222			if (!mobileOpen) return null;
223			return (
224				<>
225					<div
226						className="fixed inset-0 z-40 bg-black/45"
227						onClick={onMobileClose}
228						aria-hidden="true"
229					/>
230					<aside className="session-sidebar fixed inset-y-0 left-0 z-50 flex w-[min(22rem,85vw)] flex-col border-r-2 border-border bg-background">
231						<header className="border-b border-border px-4 py-4">
232							<div className="flex items-start justify-between gap-3">
233								<div className="min-w-0">
234									<div className="flex items-center gap-2 text-sm font-semibold">
235										<History size={15} />
236										Sessions
237									</div>
238									<p className="mt-1 text-xs leading-5 text-muted-foreground">
239										Search, fork, rename, or load a previous conversation
240									</p>
241								</div>
242								<div className="flex shrink-0 items-center gap-1">
243									<button
244										type="button"
245										className="inline-flex h-8 shrink-0 items-center justify-center rounded-md border border-border px-2 text-xs hover:bg-accent"
246										onClick={onOpenSessions}
247									>
248										Manage
249									</button>
250									{onMobileClose ? (
251										<button
252											type="button"
253											className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md border border-border text-muted-foreground hover:bg-accent hover:text-accent-foreground"
254											title="Close sessions panel"
255											aria-label="Close sessions panel"
256											onClick={onMobileClose}
257										>
258											<PanelLeftClose size={14} />
259										</button>
260									) : null}
261								</div>
262							</div>
263							<label className="mt-3 flex min-h-9 items-center gap-2 rounded-md border border-border bg-background px-3 text-xs">
264								<Search size={14} className="shrink-0 text-muted-foreground" />
265								<input
266									className="min-w-0 flex-1 bg-transparent py-2 outline-none placeholder:text-muted-foreground"
267									value={query}
268									placeholder="Search sessions"
269									onChange={(event) => setQuery(event.target.value)}
270								/>
271							</label>
272						</header>
273						<div className="min-h-0 flex-1 overflow-y-auto p-3">
274							{loading && items.length === 0 ? (
275								<div className="flex items-center justify-center gap-2 py-8 text-xs text-muted-foreground">
276									<Loader2 size={14} className="animate-spin" />
277									Loading
278								</div>
279							) : visibleItems.length === 0 ? (
280								<div className="px-2 py-8 text-center text-xs text-muted-foreground">
281									No sessions yet
282								</div>
283							) : (
284								<ul className="space-y-2" role="tree" aria-label="Session tree">
285									{visibleItems.map(({ session, depth, children }) => {
286										const active = session.id === activeSessionId;
287										const forking = session.id === forkingSessionId;
288										const justForkedSource = session.id === forkedSourceSessionId;
289										const justForked = session.id === forkedSessionId;
290										const hasChildren = children.length > 0;
291										const expanded = hasChildren && !collapsedNodes.has(session.id);
292										const showToggle = hasChildren && !isSearching;
293										return (
294											<li
295												key={session.id}
296												role="treeitem"
297												aria-level={depth + 1}
298												aria-expanded={hasChildren ? expanded : undefined}
299												className={justForked ? "session-fork-arrive" : undefined}
300												style={{ marginLeft: `${Math.min(depth, 5) * 0.9}rem` }}
301											>
302												<div
303													className={`group flex min-w-0 items-start gap-1 rounded-lg border p-3 transition-colors ${
304														active
305															? "border-primary bg-primary/10 text-primary"
306															: "border-border text-foreground hover:bg-muted/40"
307													}`}
308												>
309													{showToggle ? (
310														<button
311															type="button"
312															className="mt-0.5 inline-flex h-5 w-5 shrink-0 items-center justify-center rounded text-muted-foreground hover:bg-accent hover:text-accent-foreground"
313															title={expanded ? "Collapse forks" : "Expand forks"}
314															aria-label={expanded ? `Collapse ${children.length} fork${children.length === 1 ? "" : "s"}` : `Expand ${children.length} fork${children.length === 1 ? "" : "s"}`}
315															onClick={() => toggleNode(session.id)}
316														>
317															{expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
318														</button>
319													) : (
320														<span aria-hidden="true" className="mt-0.5 inline-block h-5 w-5 shrink-0" />
321													)}
322													<button
323														type="button"
324														className="min-w-0 flex-1 text-left"
325														onClick={() => void onLoad(session.id)}
326													>
327														<div className="flex min-w-0 items-center gap-2">
328															{session.parentSessionId ? (
329																<GitBranch size={13} className="shrink-0 text-primary" />
330															) : null}
331															<span className="truncate text-sm font-medium">{session.title}</span>
332															{hasChildren ? (
333																<span className="shrink-0 rounded bg-muted px-1.5 py-0.5 text-[10px] text-muted-foreground">
334																	{children.length}
335																</span>
336															) : null}
337															{justForkedSource ? (
338																	<span className="shrink-0 rounded bg-primary px-1.5 py-0.5 text-[10px] text-primary-foreground">
339																		Forked
340																	</span>
341																) : null}
342														</div>
343														<p className="mt-2 overflow-hidden text-xs leading-5 text-muted-foreground [display:-webkit-box] [-webkit-box-orient:vertical] [-webkit-line-clamp:2]">
344															{session.preview || "No preview saved"}
345														</p>
346														<div className="mt-3 flex flex-wrap items-center gap-2 text-[11px] text-muted-foreground">
347															<span>{session.parentSessionId ? "Fork | " : ""}{formatDate(session.lastModified)}</span>
348															<span aria-hidden="true">|</span>
349															<span>{session.messageCount} messages</span>
350														</div>
351													</button>
352													<button
353														type="button"
354														className={`inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-accent-foreground disabled:opacity-50 group-hover:opacity-100 ${
355															justForkedSource ? "text-primary opacity-100" : "opacity-0"
356														}`}
357														title={justForkedSource ? "Session forked" : "Fork session"}
358														aria-label={justForkedSource ? "Session forked" : "Fork session"}
359														disabled={forking}
360														onClick={() => void forkSession(session.id)}
361													>
362														{forking ? (
363															<Loader2 size={12} className="animate-spin" />
364														) : justForkedSource ? (
365															<Check size={12} />
366														) : (
367															<CopyPlus size={12} />
368														)}
369													</button>
370												</div>
371											</li>
372										);
373									})}
374								</ul>
375							)}
376						</div>
377					</aside>
378				</>
379			);
380		}
381	
382		/* ── Desktop collapsed strip ── */
383		if (collapsed) {
384			return (
385				<aside className="session-sidebar flex w-14 shrink-0 flex-col items-center gap-3 border-r-2 border-border bg-background py-3">
386					<button
387						type="button"
388						className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-accent hover:text-accent-foreground"
389						title="Expand sessions panel"
390						aria-label="Expand sessions panel"
391						onClick={() => onCollapsedChange?.(false)}
392					>
393						<PanelLeftOpen size={16} />
394					</button>
395					<div className="my-1 h-px w-8 bg-border" />
396					{onNewSession ? (
397						<button
398							type="button"
399							className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-accent hover:text-accent-foreground"
400							title="New session"
401							aria-label="New session"
402							onClick={onNewSession}
403						>
404							<Plus size={16} />
405						</button>
406					) : null}
407				</aside>
408			);
409		}
410	
411		/* ── Desktop expanded sidebar ── */
412		return (
413			<aside className="session-sidebar relative flex shrink-0 flex-col border-r-2 border-border bg-background" style={{ width: `${sidebarWidth}px` }}>
414				{/* Resize handle — right edge drag bar */}
415				<div
416					className="group absolute inset-y-0 right-0 z-10 flex w-2 cursor-col-resize items-center justify-center"
417					onMouseDown={handleResizeStart}
418					onTouchStart={handleResizeStart}
419				>
420					<div className="h-8 w-0.5 rounded-full bg-border opacity-0 transition-opacity group-hover:opacity-100 group-active:opacity-100" />
421				</div>
422	
423				<header className="border-b border-border px-4 py-4">
424					<div className="flex items-start gap-3">
425						<div className="flex shrink-0 items-center gap-1">
426							{onCollapsedChange ? (
427								<button
428									type="button"
429									className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md border border-border text-muted-foreground hover:bg-accent hover:text-accent-foreground"
430									title="Collapse sessions panel"
431									aria-label="Collapse sessions panel"
432									onClick={() => onCollapsedChange(true)}
433								>
434									<PanelLeftClose size={14} />
435								</button>
436							) : null}
437							<button
438								type="button"
439								className="inline-flex h-8 shrink-0 items-center justify-center rounded-md border border-border px-2 text-xs hover:bg-accent"
440								onClick={onOpenSessions}
441							>
442								Manage
443							</button>
444						</div>
445						<div className="min-w-0 flex-1 text-right">
446							<div className="flex items-center justify-end gap-2 text-sm font-semibold">
447								Sessions
448								<History size={15} />
449							</div>
450							<p className="mt-1 text-xs leading-5 text-muted-foreground">
451								Search, fork, rename, or load a previous conversation
452							</p>
453						</div>
454					</div>
455					<label className="mt-3 flex min-h-9 items-center gap-2 rounded-md border border-border bg-background px-3 text-xs">
456						<Search size={14} className="shrink-0 text-muted-foreground" />
457						<input
458							className="min-w-0 flex-1 bg-transparent py-2 outline-none placeholder:text-muted-foreground"
459							value={query}
460							placeholder="Search sessions"
461							onChange={(event) => setQuery(event.target.value)}
462						/>
463					</label>
464				</header>
465				<div className="min-h-0 flex-1 overflow-y-auto p-3">
466					{loading && items.length === 0 ? (
467						<div className="flex items-center justify-center gap-2 py-8 text-xs text-muted-foreground">
468							<Loader2 size={14} className="animate-spin" />
469							Loading
470						</div>
471					) : visibleItems.length === 0 ? (
472						<div className="px-2 py-8 text-center text-xs text-muted-foreground">
473							No sessions yet
474						</div>
475					) : (
476						<ul
477							className="space-y-2"
478							role="tree"
479							aria-label="Session tree"
480						>
481							{visibleItems.map(({ session, depth, children }) => {
482								const active = session.id === activeSessionId;
483								const forking = session.id === forkingSessionId;
484								const justForkedSource = session.id === forkedSourceSessionId;
485								const justForked = session.id === forkedSessionId;
486								const hasChildren = children.length > 0;
487								const expanded = hasChildren && !collapsedNodes.has(session.id);
488								const showToggle = hasChildren && !isSearching;
489								return (
490									<li
491										key={session.id}
492										role="treeitem"
493										aria-level={depth + 1}
494										aria-expanded={hasChildren ? expanded : undefined}
495										className={justForked ? "session-fork-arrive" : undefined}
496										style={{ marginLeft: `${Math.min(depth, 5) * 0.9}rem` }}
497									>
498										<div
499											className={`group flex min-w-0 items-start gap-1 rounded-lg border p-3 transition-colors ${
500												active
501													? "border-primary bg-primary/10 text-primary"
502													: "border-border text-foreground hover:bg-muted/40"
503											}`}
504										>
505											{showToggle ? (
506												<button
507													type="button"
508													className="mt-0.5 inline-flex h-5 w-5 shrink-0 items-center justify-center rounded text-muted-foreground hover:bg-accent hover:text-accent-foreground"
509													title={expanded ? "Collapse forks" : "Expand forks"}
510													aria-label={expanded ? `Collapse ${children.length} fork${children.length === 1 ? "" : "s"}` : `Expand ${children.length} fork${children.length === 1 ? "" : "s"}`}
511													onClick={() => toggleNode(session.id)}
512												>
513													{expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
514												</button>
515											) : (
516												<span aria-hidden="true" className="mt-0.5 inline-block h-5 w-5 shrink-0" />
517											)}
518											<button
519												type="button"
520												className="min-w-0 flex-1 text-left"
521												onClick={() => void onLoad(session.id)}
522											>
523												<div className="flex min-w-0 items-center gap-2">
524													{session.parentSessionId ? (
525														<GitBranch size={13} className="shrink-0 text-primary" />
526													) : null}
527													<span className="truncate text-sm font-medium">{session.title}</span>
528													{hasChildren ? (
529														<span className="shrink-0 rounded bg-muted px-1.5 py-0.5 text-[10px] text-muted-foreground">
530															{children.length}
531														</span>
532													) : null}
533													{justForkedSource ? (
534														<span className="shrink-0 rounded bg-primary px-1.5 py-0.5 text-[10px] text-primary-foreground">
535															Forked
536														</span>
537													) : null}
538												</div>
539												<p className="mt-2 overflow-hidden text-xs leading-5 text-muted-foreground [display:-webkit-box] [-webkit-box-orient:vertical] [-webkit-line-clamp:2]">
540													{session.preview || "No preview saved"}
541												</p>
