138								if (opt === q.correctAnswer) status = "correct";
139								else if (chosen) status = "wrong";
140							}
141							return (
142								<QuizOption
143									key={opt}
144									label={opt}
145									selected={chosen}
146									onClick={() => onChange(opt)}
147									disabled={revealed}
148									status={status}
