160	export function QuizRenderer({ quiz, onSubmit }: QuizRendererProps) {
161		const [answers, setAnswers] = useState<AnswerState>({});
162		const [revealed, setRevealed] = useState(false);
163	
164		const setAnswer = useCallback((qid: string, val: string) => {
165			setAnswers((prev) => ({ ...prev, [qid]: val }));
166		}, []);
167	
168		const score = useMemo(() => {
169			let correct = 0;
170			for (const q of quiz.questions) {
171				const ans = (answers[q.id] || "").trim().toLowerCase();
172				if (ans === q.correctAnswer.trim().toLowerCase()) correct++;
173			}
174			return correct;
175		}, [answers, quiz.questions]);
176	
177		const percent = Math.round((score / quiz.questions.length) * 100);
178	
179		const handleSubmit = useCallback(() => {
180			setRevealed(true);
181			onSubmit?.(answers, score);
182		}, [answers, score, onSubmit]);
183	
184		const handleReset = useCallback(() => {
185			setAnswers({});
186			setRevealed(false);
187		}, []);
188	
189		return (
190			<div className="rounded-xl border-2 border-border bg-background p-4 sm:p-5 space-y-4 my-3 shadow-sm">
191				<div className="flex items-center justify-between gap-2">
192					<div>
193						<h3 className="text-base font-bold">{quiz.topic}</h3>
194						<p className="text-xs text-muted-foreground font-terminal">
195							{quiz.questions.length} QUESTIONS // {quiz.totalPoints} POINTS
196						</p>
197					</div>
198					{revealed && (
199						<div className="text-right">
200							<div className={`text-2xl font-bold font-terminal ${percent >= 70 ? "text-emerald-600 dark:text-emerald-400" : percent >= 40 ? "text-amber-600 dark:text-amber-400" : "text-destructive"}`}>
201								{score}/{quiz.questions.length}
202							</div>
203							<div className="text-[10px] text-muted-foreground uppercase">{percent}%</div>
204						</div>
205					)}
206				</div>
207	
208				<div className="space-y-3">
209					{quiz.questions.map((q, i) => (
210						<QuestionCard
211							key={q.id}
212							q={q}
213							index={i}
214							answer={answers[q.id] || ""}
215							onChange={(val) => setAnswer(q.id, val)}
216							revealed={revealed}
217						/>
218					))}
219				</div>
220	
221				{!revealed ? (
222					<button
223						onClick={handleSubmit}
224						disabled={Object.keys(answers).length < quiz.questions.length}
225						className="w-full flex items-center justify-center gap-2 rounded-lg border-2 border-primary bg-primary px-4 py-2.5 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-40 disabled:pointer-events-none transition-colors"
226					>
227						<Send size={14} />
228						Submit Quiz
229					</button>
230				) : (
231					<button
232						onClick={handleReset}
233						className="w-full flex items-center justify-center gap-2 rounded-lg border-2 border-border bg-background px-4 py-2.5 text-sm font-medium hover:bg-accent transition-colors"
234					>
235						<RotateCcw size={14} />
236						Retake
237					</button>
238				)}
239			</div>
240		);
241	}
