    learningObjectives: [
      `Define ${topic.title} precisely`,
      `Apply ${topic.title} to solve unfamiliar problems`,
      `Transfer ${topic.title} to at least one new domain`,
      `Teach ${topic.title} to someone with no prior exposure`
